-- =====================================================================
-- Catalog expansion: brands (real logos) + ~126 real products
-- (loremflickr images x3, PC-builder attrs) - idempotent upserts by slug
-- =====================================================================


on conflict (slug) do update set name=excluded.name, logo_url=excluded.logo_url, sort=excluded.sort;


on conflict (slug) do update set
  name=excluded.name, brand_id=excluded.brand_id, category_id=excluded.category_id,
  price=excluded.price, old_price=excluded.old_price, sale_price=excluded.sale_price,
  stock=excluded.stock, rating=excluded.rating, reviews_count=excluded.reviews_count,
  badge=excluded.badge, images=excluded.images, specs=excluded.specs, attrs=excluded.attrs,
  is_active=true, is_featured=excluded.is_featured;

